import{_ as i,o as s,c as l,a2 as e}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"可选的可用性测试","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/validation/13-optional-usability-testing.md","filePath":"03-interaction-design/notes/validation/13-optional-usability-testing.md","lastUpdated":1784248569000}'),n={name:"03-interaction-design/notes/validation/13-optional-usability-testing.md"};function t(r,a,h,p,d,o){return s(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="可选的可用性测试" tabindex="-1">可选的可用性测试 <a class="header-anchor" href="#可选的可用性测试" aria-label="Permalink to &quot;可选的可用性测试&quot;">​</a></h1><p>可用性测试让代表性参与者使用产品或原型完成具体任务，观察任务成功、错误、理解与恢复。它是验证设计假设的一种方法，不是个人学习每次迭代的强制步骤，也不等同于用户访谈。没有招募条件时，可以先用认知走查、启发式评估、无障碍审计、公开证据、任务日志和数据验证。</p><h2 id="何时值得使用" tabindex="-1">何时值得使用 <a class="header-anchor" href="#何时值得使用" aria-label="Permalink to &quot;何时值得使用&quot;">​</a></h2><ul><li>关键问题取决于用户是否理解、发现或预测结果；</li><li>检查者对用户知识和语言存在明显不确定；</li><li>多个方案在内部评审中无法用规则决定；</li><li>高风险流程需要观察错误和恢复；</li><li>数据显示问题位置但无法解释原因；</li><li>上线前需要验证端到端任务。</li></ul><p>不适合用可用性测试替代：</p><ul><li>确定的业务规则、授权与安全校验；</li><li>自动化可验证的代码与数据不变量；</li><li>性能容量、兼容性和 WCAG 合规全量判断；</li><li>市场需求规模或统计因果实验。</li></ul><h2 id="测试形式" tabindex="-1">测试形式 <a class="header-anchor" href="#测试形式" aria-label="Permalink to &quot;测试形式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>形式</th><th>特点</th><th>适用</th><th>限制</th></tr></thead><tbody><tr><td>主持远程/现场</td><td>可观察并追问关键理解</td><td>复杂流程、早期原型、恢复</td><td>主持影响行为，安排成本较高</td></tr><tr><td>非主持远程</td><td>按脚本独立完成</td><td>稳定原型、入口与任务结果</td><td>难以理解卡点原因，需可靠埋点</td></tr><tr><td>走廊/同伴测试</td><td>快速取得初步反馈</td><td>明显发现与文案问题</td><td>参与者通常不代表目标用户</td></tr><tr><td>基准任务</td><td>使用稳定任务与指标重复测量</td><td>版本前后比较</td><td>需控制任务、样本与学习效应</td></tr></tbody></table><p>选择形式取决于问题，不应为了追求“正式”增加无关环节。</p><h2 id="基本流程" tabindex="-1">基本流程 <a class="header-anchor" href="#基本流程" aria-label="Permalink to &quot;基本流程&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;研究问题与风险&quot;] --&gt; P[&quot;参与者、任务与原型&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; S[&quot;试运行脚本和数据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; T[&quot;执行并观察&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T --&gt; A[&quot;按行为和结果分析&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; D[&quot;修复、补证与复测&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="写研究问题" tabindex="-1">写研究问题 <a class="header-anchor" href="#写研究问题" aria-label="Permalink to &quot;写研究问题&quot;">​</a></h2><p>研究问题必须可观察：</p><ul><li>用户能否从通知进入正确任务？</li><li>用户怎样区分上传完成与处理完成？</li><li>部分成功后能否只修正失败项？</li><li>用户能否在无鼠标时定位和修正错误？</li></ul><p>“用户喜欢哪个颜色”“这个设计是否直观”不能直接指导任务验证。</p><h2 id="参与者条件" tabindex="-1">参与者条件 <a class="header-anchor" href="#参与者条件" aria-label="Permalink to &quot;参与者条件&quot;">​</a></h2><p>根据任务选择必要条件：</p><ul><li>角色、经验、设备和语言；</li><li>是否使用辅助技术；</li><li>是否具备任务所需知识；</li><li>不需要收集的敏感人口信息应避免收集。</li></ul><p>样本数量取决于研究问题、用户差异、风险和迭代方式。不存在适用于所有测试的固定人数。小样本适合发现问题，不适合精确估计总体发生率。</p><h2 id="任务设计" tabindex="-1">任务设计 <a class="header-anchor" href="#任务设计" aria-label="Permalink to &quot;任务设计&quot;">​</a></h2><p>任务包含场景、目标、输入和完成结果，不提供界面步骤。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你负责 Roadmap 项目。请把 li@example.com 和 wang@example.com 邀请为编辑者，并确认邀请结果。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>不要写：“点击右上角邀请按钮，粘贴邮箱并提交。”</p><h3 id="固定数据" tabindex="-1">固定数据 <a class="header-anchor" href="#固定数据" aria-label="Permalink to &quot;固定数据&quot;">​</a></h3><p>准备真实长度、无效、重复、权限和错误数据。每位参与者使用独立或可重置账户，防止前一场结果污染后一场。</p><h3 id="完成标准" tabindex="-1">完成标准 <a class="header-anchor" href="#完成标准" aria-label="Permalink to &quot;完成标准&quot;">​</a></h3><p>在测试前定义成功、错误成功、部分成功、失败、放弃、结果未知和非计划帮助。</p><h2 id="主持与观察" tabindex="-1">主持与观察 <a class="header-anchor" href="#主持与观察" aria-label="Permalink to &quot;主持与观察&quot;">​</a></h2><h3 id="开场" tabindex="-1">开场 <a class="header-anchor" href="#开场" aria-label="Permalink to &quot;开场&quot;">​</a></h3><p>说明测试的是产品而不是参与者；可以随时停止；如何录制、保存与使用数据；不要索取真实密码、支付和敏感信息。</p><h3 id="中性提示" tabindex="-1">中性提示 <a class="header-anchor" href="#中性提示" aria-label="Permalink to &quot;中性提示&quot;">​</a></h3><p>当参与者停住时，可说“请说说你现在在找什么”或“你认为刚才发生了什么”。不要提示按钮位置、肯定答案或解释设计。</p><h3 id="出声思考" tabindex="-1">出声思考 <a class="header-anchor" href="#出声思考" aria-label="Permalink to &quot;出声思考&quot;">​</a></h3><p>可用于理解预测和判断，但会改变自然节奏与时间。若时间是主要指标，减少持续口述，改在关键节点追问。</p><h3 id="记录" tabindex="-1">记录 <a class="header-anchor" href="#记录" aria-label="Permalink to &quot;记录&quot;">​</a></h3><ul><li>首次动作和路径；</li><li>预测、判断与实际结果；</li><li>错误、返回、绕过和恢复；</li><li>帮助的具体内容；</li><li>系统或原型故障；</li><li>任务结果与权威数据。</li></ul><p>观察事实与解释分开。皱眉不能直接编码为“困惑”，应记录停顿、返回和说出的理解。</p><h2 id="伦理、隐私与安全" tabindex="-1">伦理、隐私与安全 <a class="header-anchor" href="#伦理、隐私与安全" aria-label="Permalink to &quot;伦理、隐私与安全&quot;">​</a></h2><ul><li>取得明确同意并说明录制、用途、保留与撤回；</li><li>只收集研究问题需要的数据；</li><li>使用测试账户、合成数据和安全环境；</li><li>不记录密码、验证码、支付信息和真实敏感文件；</li><li>限制录像、转录与日志访问，按计划删除；</li><li>为无障碍需求提供合理安排；</li><li>高风险任务不让参与者承担真实损失。</li></ul><p>个人学习邀请朋友参与也应尊重同意与隐私，不因非商业项目降低标准。</p><h2 id="分析方法" tabindex="-1">分析方法 <a class="header-anchor" href="#分析方法" aria-label="Permalink to &quot;分析方法&quot;">​</a></h2><h3 id="先按任务结果" tabindex="-1">先按任务结果 <a class="header-anchor" href="#先按任务结果" aria-label="Permalink to &quot;先按任务结果&quot;">​</a></h3><p>每场标记成功类别、严重错误、帮助和恢复。实际对象状态优先于参与者口头“完成了”。</p><h3 id="再按机制聚类" tabindex="-1">再按机制聚类 <a class="header-anchor" href="#再按机制聚类" aria-label="Permalink to &quot;再按机制聚类&quot;">​</a></h3><p>将问题按入口、术语、信息层级、状态、错误、权限和恢复聚类。不要按参与者评价好坏计票。</p><h3 id="证据强度" tabindex="-1">证据强度 <a class="header-anchor" href="#证据强度" aria-label="Permalink to &quot;证据强度&quot;">​</a></h3><p>记录出现在哪些角色、任务和条件下；单次严重数据风险即使频率低也值得优先处理。小样本不计算精确总体百分比。</p><h3 id="与其他数据结合" tabindex="-1">与其他数据结合 <a class="header-anchor" href="#与其他数据结合" aria-label="Permalink to &quot;与其他数据结合&quot;">​</a></h3><p>行为数据检查范围，支持问题检查长期影响，日志解释工程机制，无障碍审计检查规范。可用性测试不替代这些方法。</p><h2 id="完整案例-测试部分成功的成员邀请" tabindex="-1">完整案例：测试部分成功的成员邀请 <a class="header-anchor" href="#完整案例-测试部分成功的成员邀请" aria-label="Permalink to &quot;完整案例：测试部分成功的成员邀请&quot;">​</a></h2><h3 id="研究问题" tabindex="-1">研究问题 <a class="header-anchor" href="#研究问题" aria-label="Permalink to &quot;研究问题&quot;">​</a></h3><ol><li>项目管理员能否一次输入多个邮箱？</li><li>能否理解有效、已有成员、无效和服务失败的不同结果？</li><li>能否只重试失败项，避免重复邀请？</li></ol><h3 id="参与者与环境" tabindex="-1">参与者与环境 <a class="header-anchor" href="#参与者与环境" aria-label="Permalink to &quot;参与者与环境&quot;">​</a></h3><p>计划邀请 4 名日常管理项目但未用过此功能的参与者；结果仅用于问题发现，不估计总体比例。使用桌面 Chrome；其中一场要求仅用键盘，以检查路径问题，但完整无障碍结论由单独审计提供。</p><h3 id="固定任务数据" tabindex="-1">固定任务数据 <a class="header-anchor" href="#固定任务数据" aria-label="Permalink to &quot;固定任务数据&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>li@example.com：有效</span></span>
<span class="line"><span>wang@example.com：有效</span></span>
<span class="line"><span>bad-address：格式错误</span></span>
<span class="line"><span>member@example.com：已是成员</span></span>
<span class="line"><span>timeout@example.com：暂时服务失败</span></span>
<span class="line"><span>角色：编辑者</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>完成标准：修正格式后创建 3 个新邀请；已有成员不重复；超时项重试后成功；最终成员页可确认。</p><h3 id="任务脚本" tabindex="-1">任务脚本 <a class="header-anchor" href="#任务脚本" aria-label="Permalink to &quot;任务脚本&quot;">​</a></h3><p>“你需要让给定的 5 个地址参与 Roadmap 项目，并能够编辑任务。请处理所有地址，确认哪些已经生效、哪些仍需处理。”</p><h3 id="观察记录示例" tabindex="-1">观察记录示例 <a class="header-anchor" href="#观察记录示例" aria-label="Permalink to &quot;观察记录示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>步骤</th><th>事实</th><th>解释假设</th></tr></thead><tbody><tr><td>粘贴</td><td>5 行正确拆分</td><td>多值输入可理解</td></tr><tr><td>提交</td><td><code>bad-address</code> 错误出现后修正</td><td>错误文本支持恢复</td></tr><tr><td>结果</td><td>参与者把“已有成员”也当新邀请</td><td>结果分组/术语可能不清</td></tr><tr><td>重试</td><td>选择“重新提交全部”</td><td>与“只重试失败项”动作难区分</td></tr><tr><td>检查</td><td>成员页出现 3 个待接受</td><td>权威结果正确</td></tr></tbody></table><h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h3><ul><li>分组为“新邀请已发送”“已经是成员”“需要重试”；</li><li>每组显示数量与对象；</li><li>只提供一个主要动作“重试 1 个失败项”；</li><li>已成功项移出可提交集合；</li><li>状态消息朗读完整结果而不是“成功”。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>一场中原型服务不可用，所有结果变为失败。该场标记为系统故障，不计入设计任务结果；保留观察到的错误恢复证据。另一场参与者因测试账户已有残留邀请看到不同结果，说明数据重置流程失败，必须重置后重测。</p><h3 id="输出边界" tabindex="-1">输出边界 <a class="header-anchor" href="#输出边界" aria-label="Permalink to &quot;输出边界&quot;">​</a></h3><p>可以写：“在这组任务中，多名参与者把‘已有成员’误解为新邀请，且‘重新提交全部’导致错误选择；修复后需复测。”不能写：“所有用户都不理解部分成功。”</p><h2 id="测试报告模板" tabindex="-1">测试报告模板 <a class="header-anchor" href="#测试报告模板" aria-label="Permalink to &quot;测试报告模板&quot;">​</a></h2><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 研究问题：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 参与者条件与数量：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 环境/版本/原型限制：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 任务/输入/完成标准：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 同意与数据处理：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 任务结果：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 行为事实：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 机制假设：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 严重性与范围：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 系统/原型故障：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 修复与复测计划：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 不能推断：</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="没有参与者时的替代路径" tabindex="-1">没有参与者时的替代路径 <a class="header-anchor" href="#没有参与者时的替代路径" aria-label="Permalink to &quot;没有参与者时的替代路径&quot;">​</a></h2><ol><li>用认知走查检查首次行动和反馈。</li><li>用启发式评估检查通用原则。</li><li>用 WCAG 审计检查键盘、语义、缩放和状态。</li><li>用公开 Issue、支持和数据寻找真实问题线索。</li><li>用自用任务日志与边界条件检查动态行为。</li><li>把仍需真实理解证据的问题放入未来测试清单。</li></ol><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>把可用性测试等同用户访谈：以任务行为为核心。</li><li>任务泄露路径：删除页面和按钮名称。</li><li>参与者使用真实账户与敏感数据：提供测试环境。</li><li>主持人立即帮助或解释：使用中性提示并记录帮助。</li><li>原型故障算用户失败：单独分类并重测。</li><li>小样本计算精确总体比例。</li><li>只听偏好，不检查任务权威结果。</li><li>认为没有条件测试就停止迭代：使用替代验证方法。</li></ul><h2 id="可执行步骤" tabindex="-1">可执行步骤 <a class="header-anchor" href="#可执行步骤" aria-label="Permalink to &quot;可执行步骤&quot;">​</a></h2><ol><li>判断问题是否需要真实任务理解证据。</li><li>写研究问题、参与者条件、风险和数据处理。</li><li>准备不泄露路径的任务、固定数据与完成标准。</li><li>试运行原型、账户重置和失败状态。</li><li>使用中性脚本观察动作、判断、错误和恢复。</li><li>分离行为事实、解释、帮助和系统故障。</li><li>按机制聚类并结合日志、规范和数据补证。</li><li>修复后使用相同任务、口径和安全条件复测。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为“首次创建并保存恢复代码”写一份可选可用性测试计划。</p><p>完成时应满足：</p><ul><li>研究问题聚焦发现、理解、保存和恢复，不询问泛化喜好；</li><li>参与者条件与样本用途明确，不承诺代表总体；</li><li>任务不泄露设置路径；</li><li>使用测试账户和合成代码，不记录真实认证信息；</li><li>成功标准含重新进入和恢复结果；</li><li>覆盖验证码错误、下载失败和会话过期；</li><li>同时写明没有参与者时的认知走查、无障碍与边界替代方案。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.gov.uk/service-manual/user-research/plan-user-research-for-your-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Planning user research</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/user-research/using-moderated-usability-testing" target="_blank" rel="noreferrer">GOV.UK Service Manual：Using moderated usability testing</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/usability-benchmarking-a-website-or-whole-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Usability benchmarking a website or whole service</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/test-evaluate/involving-users/" target="_blank" rel="noreferrer">W3C WAI：Involving Users in Evaluating Web Accessibility</a>（访问日期：2026-07-17）</li></ul>`,81)])])}const b=i(n,[["render",t]]);export{u as __pageData,b as default};
